import React, { useState } from 'react';
import DragDropCanvas from './components/DragDropCanvas';
import VisualizationLibrary from './components/VisualizationLibrary';
import ExportManager from './components/ExportManager';
import DataConnections from './components/DataConnections';
import VariablesView from './components/VariablesView';
import CodeEditor from './components/CodeEditor';
import PageTabs from './components/PageTabs';
import { WindowPanel, BackgroundConfig, DataConnection, CodeEditorConfig, PageConfig, ProjectConfig } from './types';
import './App.css';

const App: React.FC = () => {
  // Initialize with default page
  const [project, setProject] = useState<ProjectConfig>({
    pages: [
      {
        id: 'page-1',
        name: 'Page 1',
        windows: [],
        backgroundConfig: {
          width: 1200,
          height: 800,
          color: '#ffffff'
        },
        codeEditorConfigs: [
          {
            id: 'default-config',
            name: 'Default Editor',
            elements: [],
            htmlCode: '',
            jsCode: '',
            cssCode: ''
          }
        ]
      }
    ],
    activePageId: 'page-1',
    dataConnections: {
      apiConnections: [],
      globalVariables: {}
    }
  });

  const [activeTab, setActiveTab] = useState<'builder' | 'data' | 'variables' | 'editor'>('builder');
  const [leftPanelVisible, setLeftPanelVisible] = useState<boolean>(true);
  const [rightPanelVisible, setRightPanelVisible] = useState<boolean>(true);

  // Helper functions to get current page data
  const getCurrentPage = (): PageConfig => {
    return project.pages.find(p => p.id === project.activePageId) || project.pages[0];
  };

  const windows = getCurrentPage().windows;
  const backgroundConfig = getCurrentPage().backgroundConfig;
  const codeEditorConfigs = getCurrentPage().codeEditorConfigs;
  const dataConnections = project.dataConnections;

  // Page management functions
  const handlePageSelect = (pageId: string) => {
    setProject(prev => ({
      ...prev,
      activePageId: pageId
    }));
  };

  const handlePageAdd = () => {
    const newPageId = `page-${Date.now()}`;
    const newPage: PageConfig = {
      id: newPageId,
      name: `Page ${project.pages.length + 1}`,
      windows: [],
      backgroundConfig: {
        width: 1200,
        height: 800,
        color: '#ffffff'
      },
      codeEditorConfigs: [
        {
          id: `config-${Date.now()}`,
          name: 'Default Editor',
          elements: [],
          htmlCode: '',
          jsCode: '',
          cssCode: ''
        }
      ]
    };

    setProject(prev => ({
      ...prev,
      pages: [...prev.pages, newPage],
      activePageId: newPageId
    }));
  };

  const handlePageRename = (pageId: string, newName: string) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(page =>
        page.id === pageId ? { ...page, name: newName } : page
      )
    }));
  };

  const handlePageDelete = (pageId: string) => {
    if (project.pages.length <= 1) return; // Don't delete the last page

    setProject(prev => {
      const remainingPages = prev.pages.filter(page => page.id !== pageId);
      const newActivePageId = prev.activePageId === pageId 
        ? remainingPages[0].id 
        : prev.activePageId;

      return {
        ...prev,
        pages: remainingPages,
        activePageId: newActivePageId
      };
    });
  };

  // Updated handler functions for current page
  const setWindows = (newWindows: WindowPanel[] | ((prev: WindowPanel[]) => WindowPanel[])) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(page =>
        page.id === prev.activePageId
          ? {
              ...page,
              windows: typeof newWindows === 'function' ? newWindows(page.windows) : newWindows
            }
          : page
      )
    }));
  };

  const setBackgroundConfig = (newConfig: BackgroundConfig) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(page =>
        page.id === prev.activePageId
          ? { ...page, backgroundConfig: newConfig }
          : page
      )
    }));
  };

  const setDataConnections = (newConnections: DataConnection) => {
    setProject(prev => ({
      ...prev,
      dataConnections: newConnections
    }));
  };

  const setCodeEditorConfigs = (newConfigs: CodeEditorConfig[]) => {
    setProject(prev => ({
      ...prev,
      pages: prev.pages.map(page =>
        page.id === prev.activePageId
          ? { ...page, codeEditorConfigs: newConfigs }
          : page
      )
    }));
  };

  const handleAddTemplate = (type: 'javascript' | 'html', template: any) => {
    const newWindow: WindowPanel = {
      id: `window-${Date.now()}`,
      title: template.name,
      type,
      content: type === 'html' ? template.code : '',
      position: { 
        x: Math.random() * 300 + 50, 
        y: Math.random() * 200 + 50 
      },
      size: { width: 400, height: 300 },
      jsCode: type === 'javascript' ? template.code : undefined
    };

    setWindows(prev => [...prev, newWindow]);
  };

  const handleWindowsChange = (newWindows: WindowPanel[]) => {
    setWindows(newWindows);
  };

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      flexDirection: 'column',
      fontFamily: '"Segoe UI", "Arial", sans-serif',
      backgroundColor: '#f7f8fa',
      color: '#2c3e50'
    }}>
      {/* Header */}
      <header style={{
        padding: '15px 20px',
        backgroundColor: '#1a1a1a',
        color: 'white',
        borderBottom: '3px solid #0066cc',
        boxShadow: '0 2px 8px rgba(0,0,0,0.15)'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <img 
            src="/evs-logo.png" 
            alt="EVS Automation" 
            style={{ 
              height: '65px', 
              width: 'auto'
            }} 
          />
          <div>
            <h1 style={{ 
              margin: 0, 
              fontSize: '28px',
              fontWeight: '700',
              letterSpacing: '0.5px',
              fontFamily: '"Segoe UI", "Arial Black", sans-serif'
            }}>
              Web App & HMI Builder
            </h1>
            <p style={{ 
              margin: '2px 0 0 0', 
              fontSize: '13px', 
              opacity: 0.85,
              fontWeight: '500',
              letterSpacing: '0.3px',
              textTransform: 'uppercase'
            }}>
              Industrial Web Applications & Data Visualization
            </p>
          </div>
        </div>
      </header>

      {/* Page Tabs */}
      <PageTabs
        pages={project.pages}
        activePageId={project.activePageId}
        onPageSelect={handlePageSelect}
        onPageAdd={handlePageAdd}
        onPageRename={handlePageRename}
        onPageDelete={handlePageDelete}
      />

      {/* Tab Navigation */}
      <div style={{
        borderBottom: '2px solid #e9ecef',
        backgroundColor: '#f1f3f4',
        boxShadow: 'inset 0 -1px 0 rgba(0,0,0,0.1)'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingLeft: '20px', paddingRight: '20px' }}>
          <div style={{ display: 'flex' }}>
            <button
              onClick={() => setActiveTab('builder')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'builder' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'builder' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'builder' ? '700' : '600',
                color: activeTab === 'builder' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
              BUILDER
            </button>
            <button
              onClick={() => setActiveTab('data')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'data' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'data' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'data' ? '700' : '600',
                color: activeTab === 'data' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
              DATA CONNECTIONS
            </button>
            <button
              onClick={() => setActiveTab('variables')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'variables' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'variables' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'variables' ? '700' : '600',
                color: activeTab === 'variables' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
              VARIABLES
            </button>
            <button
              onClick={() => setActiveTab('editor')}
              style={{
                padding: '14px 24px',
                backgroundColor: activeTab === 'editor' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'editor' ? '3px solid #0066cc' : '3px solid transparent',
                fontSize: '15px',
                fontWeight: activeTab === 'editor' ? '700' : '600',
                color: activeTab === 'editor' ? '#0066cc' : '#495057',
                cursor: 'pointer',
                borderRadius: '6px 6px 0 0',
                letterSpacing: '0.3px',
                fontFamily: '"Segoe UI", "Arial", sans-serif',
                textTransform: 'uppercase',
                transition: 'all 0.2s ease'
              }}
            >
              EDITOR
            </button>
          </div>

        </div>
      </div>

      {/* Main Layout */}
      <div style={{
        flex: 1,
        display: 'flex',
        overflow: 'hidden'
      }}>
        {activeTab === 'builder' ? (
          <>
            {/* Left Sidebar - Templates */}
            {leftPanelVisible && (
              <div 
                style={{
                  width: '250px',
                  backgroundColor: '#f7f8fa',
                  borderRight: '2px solid #d6dbdf',
                  overflow: 'auto',
                  transition: 'width 0.3s ease, z-index 0s 0.3s',
                  position: 'relative',
                  zIndex: 1,
                  minWidth: '250px',
                  boxShadow: 'inset -1px 0 0 rgba(0,102,204,0.1)'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.width = '350px';
                  e.currentTarget.style.zIndex = '10';
                  e.currentTarget.style.boxShadow = '2px 0 12px rgba(0,102,204,0.15), inset -1px 0 0 rgba(0,102,204,0.2)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.width = '250px';
                  e.currentTarget.style.zIndex = '1';
                  e.currentTarget.style.boxShadow = 'inset -1px 0 0 rgba(0,102,204,0.1)';
                }}
              >
                {/* Clickable Tab Header */}
                <div 
                  onClick={() => setLeftPanelVisible(false)}
                  style={{
                    padding: '12px 16px',
                    backgroundColor: '#0066cc',
                    color: 'white',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    borderBottom: '1px solid #d6dbdf',
                    fontFamily: '"Segoe UI", "Arial", sans-serif',
                    userSelect: 'none'
                  }}
                >
                  <span>TEMPLATES</span>
                  <span style={{ fontSize: '12px' }}>◀</span>
                </div>
                <VisualizationLibrary onAddTemplate={handleAddTemplate} />
              </div>
            )}

            {/* Left Panel Collapsed Tab */}
            {!leftPanelVisible && (
              <div 
                onClick={() => setLeftPanelVisible(true)}
                style={{
                  width: '32px',
                  backgroundColor: '#0066cc',
                  borderRight: '2px solid #d6dbdf',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  position: 'relative',
                  zIndex: 1,
                  transition: 'all 0.3s ease'
                }}
              >
                <div style={{
                  color: 'white',
                  fontSize: '14px',
                  fontWeight: '600',
                  writingMode: 'vertical-lr',
                  textOrientation: 'mixed',
                  fontFamily: '"Segoe UI", "Arial", sans-serif',
                  userSelect: 'none',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span style={{ fontSize: '12px' }}>▶</span>
                  <span>TEMPLATES</span>
                </div>
              </div>
            )}

            {/* Center - Canvas */}
            <div style={{ 
              flex: 1, 
              overflow: 'auto',
              minWidth: '400px'
            }}>
              <DragDropCanvas 
                windows={windows}
                onWindowsChange={handleWindowsChange}
                backgroundConfig={backgroundConfig}
                onBackgroundConfigChange={setBackgroundConfig}
                dataConnections={dataConnections}
              />
            </div>

            {/* Right Sidebar - Export */}
            {rightPanelVisible && (
              <div 
                style={{
                  width: '250px',
                  backgroundColor: '#f7f8fa',
                  borderLeft: '2px solid #d6dbdf',
                  overflow: 'auto',
                  transition: 'width 0.3s ease, z-index 0s 0.3s',
                  position: 'relative',
                  zIndex: 1,
                  minWidth: '250px',
                  boxShadow: 'inset 1px 0 0 rgba(0,102,204,0.1)'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.width = '350px';
                  e.currentTarget.style.zIndex = '10';
                  e.currentTarget.style.boxShadow = '-2px 0 12px rgba(0,102,204,0.15), inset 1px 0 0 rgba(0,102,204,0.2)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.width = '250px';
                  e.currentTarget.style.zIndex = '1';
                  e.currentTarget.style.boxShadow = 'inset 1px 0 0 rgba(0,102,204,0.1)';
                }}
              >
                {/* Clickable Tab Header */}
                <div 
                  onClick={() => setRightPanelVisible(false)}
                  style={{
                    padding: '12px 16px',
                    backgroundColor: '#0066cc',
                    color: 'white',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    borderBottom: '1px solid #d6dbdf',
                    fontFamily: '"Segoe UI", "Arial", sans-serif',
                    userSelect: 'none'
                  }}
                >
                  <span>EXPORT</span>
                  <span style={{ fontSize: '12px' }}>▶</span>
                </div>
                <ExportManager 
                  project={project}
                  onProjectChange={setProject}
                  windows={windows} 
                  backgroundConfig={backgroundConfig}
                  onBackgroundConfigChange={setBackgroundConfig}
                  dataConnections={dataConnections}
                  onWindowsChange={setWindows}
                  onDataConnectionsChange={setDataConnections}
                  codeEditorConfigs={codeEditorConfigs}
                  onCodeEditorConfigsChange={setCodeEditorConfigs}
                />
              </div>
            )}

            {/* Right Panel Collapsed Tab */}
            {!rightPanelVisible && (
              <div 
                onClick={() => setRightPanelVisible(true)}
                style={{
                  width: '32px',
                  backgroundColor: '#0066cc',
                  borderLeft: '2px solid #d6dbdf',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  position: 'relative',
                  zIndex: 1,
                  transition: 'all 0.3s ease'
                }}
              >
                <div style={{
                  color: 'white',
                  fontSize: '14px',
                  fontWeight: '600',
                  writingMode: 'vertical-lr',
                  textOrientation: 'mixed',
                  fontFamily: '"Segoe UI", "Arial", sans-serif',
                  userSelect: 'none',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <span>EXPORT</span>
                  <span style={{ fontSize: '12px' }}>◀</span>
                </div>
              </div>
            )}
          </>
        ) : activeTab === 'data' ? (
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f7f8fa',
            fontFamily: '"Segoe UI", "Arial", sans-serif'
          }}>
            <DataConnections
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
            />
          </div>
        ) : activeTab === 'variables' ? (
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f7f8fa',
            fontFamily: '"Segoe UI", "Arial", sans-serif'
          }}>
            <VariablesView
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
            />
          </div>
        ) : activeTab === 'editor' ? (
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f7f8fa',
            fontFamily: '"Segoe UI", "Arial", sans-serif'
          }}>
            <CodeEditor
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
              configs={codeEditorConfigs}
              onConfigsChange={setCodeEditorConfigs}
            />
          </div>
        ) : null}
      </div>
    </div>
  );
};

export default App;
